const items = $input.all();

const warehouses = {};

for (const item of items) {

    const warehouse = item.json.Warehouse;

    if (!warehouses[warehouse]) {

        warehouses[warehouse] = {

            Warehouse: warehouse,
            Total_Products: 0,
            Critical_Products: 0,
            High_Products: 0,
            Total_Inventory_Value: 0,
            Total_Days: 0,
            Overstock: 0,
            Understock: 0,
            Dead_Stock: 0,
            Slow_Moving: 0

        };

    }

    const w = warehouses[warehouse];

    w.Total_Products++;

    if (item.json.Risk_Level === "Critical")
        w.Critical_Products++;

    if (item.json.Risk_Level === "High")
        w.High_Products++;

    w.Total_Inventory_Value += Number(item.json.Inventory_Value_USD || 0);

    w.Total_Days += Number(item.json.Days_To_Stockout || 0);

    const stock = Number(item.json.Current_Stock);
    const safety = Number(item.json.Safety_Stock);
    const demand = Number(item.json.Daily_Demand);

    // Understock
    if (stock < safety)
        w.Understock++;

    // Overstock
    if (stock > (safety * 3))
        w.Overstock++;

    // Dead Stock
    if (demand === 0)
        w.Dead_Stock++;

    // Slow Moving
    if (demand > 0 && demand < 3)
        w.Slow_Moving++;

}

const output = [];

for (const key in warehouses) {

    const w = warehouses[key];

    const avgDays = w.Total_Days / w.Total_Products;

    let risk = "";
    let recommendation = "";

    if (w.Critical_Products >= 5) {

        risk = "Critical";

        recommendation =
        "Immediate replenishment and warehouse review required.";

    }
    else if (w.High_Products >= 5) {

        risk = "High";

        recommendation =
        "Increase inventory monitoring and procurement planning.";

    }
    else {

        risk = "Normal";

        recommendation =
        "Warehouse operating within acceptable limits.";

    }

    output.push({

        json: {

            Warehouse: w.Warehouse,

            Total_Products: w.Total_Products,

            Critical_Products: w.Critical_Products,

            High_Products: w.High_Products,

            Total_Inventory_Value:
                Number(w.Total_Inventory_Value.toFixed(2)),

            Average_Days_To_Stockout:
                Number(avgDays.toFixed(2)),

            Overstock_Products: w.Overstock,

            Understock_Products: w.Understock,

            Dead_Stock: w.Dead_Stock,

            Slow_Moving: w.Slow_Moving,

            Warehouse_Risk: risk,

            Recommended_Action: recommendation

        }

    });

}

return output;

const item = $json;

const totalProducts = Number(item.Total_Products || 0);
const critical = Number(item.Critical_Products || 0);
const high = Number(item.High_Products || 0);
const overstock = Number(item.Overstock_Products || 0);
const understock = Number(item.Understock_Products || 0);
const deadStock = Number(item.Dead_Stock || 0);
const slowMoving = Number(item.Slow_Moving || 0);
const avgDays = Number(item.Average_Days_To_Stockout || 0);

let score = 100;

// ===========================
// Penalty Scoring
// ===========================

score -= critical * 5;
score -= high * 2.5;
score -= overstock * 2;
score -= understock * 3;
score -= deadStock * 4;
score -= slowMoving * 1.5;

// Days to Stockout

if (avgDays < 5)
    score -= 20;
else if (avgDays < 10)
    score -= 10;
else if (avgDays < 20)
    score -= 5;

// Keep score between 0 and 100

score = Math.max(0, Math.min(100, Math.round(score)));


// ===========================
// Health Classification
// ===========================

let health = "";
let recommendation = "";
let optimization = "";

if (score >= 90) {

    health = "Excellent";
    recommendation = "Inventory operating normally.";
    optimization = "Maintain Current Inventory";

}
else if (score >= 75) {

    health = "Good";
    recommendation = "Minor optimization required.";
    optimization = "Fine Tune Inventory";

}
else if (score >= 60) {

    health = "Moderate";
    recommendation = "Inventory needs attention.";
    optimization = "Rebalance Inventory";

}
else if (score >= 40) {

    health = "Poor";
    recommendation = "Immediate corrective action required.";
    optimization = "Reduce Stockout Risk";

}
else {

    health = "Critical";
    recommendation = "Urgent inventory optimization required.";
    optimization = "Emergency Inventory Recovery";

}

// Save Results

item.Inventory_Health_Score = score;
item.Inventory_Health = health;
item.Optimization_Recommendation = recommendation;
item.Inventory_Optimization = optimization;

return {
    json: item
};

